acceptance_tests.test_rate_table.py:
import pytest
from rate_table import DEFAULT_RATES, load_rates, cost

def test_default_rates_present():
    for m in ['gpt-4o','gpt-4o-mini','claude-haiku','claude-sonnet']:
        assert m in DEFAULT_RATES
        assert isinstance(DEFAULT_RATES[m], float)

def test_load_rates_merge_and_no_mutate():
    overrides = {'gpt-4o': 9.99, 'custom-model': 1.0}
    merged = load_rates(overrides)
    assert merged['gpt-4o'] == 9.99
    assert merged['custom-model'] == 1.0
    assert merged['gpt-4o-mini'] == DEFAULT_RATES['gpt-4o-mini']
    assert DEFAULT_RATES['gpt-4o'] != 9.99

def test_cost_basic():
    assert cost('gpt-4o-mini', 1000) == 0.15
    assert cost('claude-sonnet', 500) == 1.5

def test_cost_with_custom_rates():
    rates = {'foo': 2.0}
    assert cost('foo', 2000, rates=rates) == 4.0

def test_cost_unknown_model_raises():
    with pytest.raises(KeyError):
        cost('unknown-model-xyz', 100)

