files.rate_lookup.py:
def get_rate(model, rate_table):
    if model in rate_table:
        return rate_table[model]
    if 'default' in rate_table:
        return rate_table['default']
    raise KeyError(model)


def cost(model, tokens, rate_table):
    rate = get_rate(model, rate_table)
    return rate * tokens / 100.0

