acceptance_tests.test_rate_lookup.py:
import pytest
from rate_lookup import get_rate, cost

def test_known_model():
    rt = {'gpt': 0.02, 'default': 0.01}
    assert get_rate('gpt', rt) == 0.02

def test_fallback_default():
    rt = {'gpt': 0.02, 'default': 0.01}
    assert get_rate('unknown', rt) == 0.01

def test_no_default_raises():
    rt = {'gpt': 0.02}
    with pytest.raises(KeyError):
        get_rate('unknown', rt)

def test_cost_computation():
    rt = {'gpt': 0.02, 'default': 0.01}
    assert cost('gpt', 100, rt) == 2.0
    assert cost('other', 50, rt) == 0.5

