class BudgetTracker:
    def __init__(self):
        self.records = []

    def add_spend(self, agent_id, amount):
        self.records.append((agent_id, amount))

def export_csv(tracker):
    lines = ['agent_id,amount']
    for agent_id, amount in tracker.records:
        lines.append(f'{agent_id},{amount}')
    return '\n'.join(lines) + '\n'

