def check_alert(spend, threshold):
    """Return True if spend has reached or exceeded the threshold."""
    return spend >= threshold


def alert_message(spend, threshold):
    """Return a human-readable status message for the given spend/threshold."""
    if check_alert(spend, threshold):
        return f"ALERT: spend {spend} has reached or exceeded threshold {threshold}"
    return f"OK: spend {spend} is within threshold {threshold}"

